async (page) => {
  // Try direct canvas click on the object at (121,203)
  // Player is at (120,203), object is 1 tile east → screen x=648+48=696, y=384
  const beforeChat = await page.evaluate(() => window.__latestGameState?.ui_state?.recent_chat?.join('|') || '');
  const beforeInv = await page.evaluate(() => JSON.stringify(window.__latestGameState?.inventory?.length));

  await page.evaluate(({x, y}) => {
    const canvas = document.getElementById('canvas');
    canvas.dispatchEvent(new MouseEvent('mousedown', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    canvas.dispatchEvent(new MouseEvent('mouseup', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
  }, { x: 696, y: 384 });

  await page.waitForTimeout(3000);

  const afterChat = await page.evaluate(() => window.__latestGameState?.ui_state?.recent_chat?.join('|') || '');
  const afterInv = await page.evaluate(() => JSON.stringify(window.__latestGameState?.inventory));
  const pos = await page.evaluate(() => ({ x: window.game.player.gridX, y: window.game.player.gridY }));

  return JSON.stringify({ beforeChat, afterChat, chatChanged: beforeChat !== afterChat, pos, invCount: JSON.parse(afterInv)?.length });
}

async (page) => {
  const info = await page.evaluate(() => {
    const player = window.game.player;
    const socket = window.game.socket;

    // Check player.step and update methods that trigger when near object
    let proto = Object.getPrototypeOf(player);
    let stepSrc = '';
    while (proto && proto !== Object.prototype) {
      if (proto.hasOwnProperty('step')) { stepSrc = proto.step.toString().substring(0, 400); break; }
      proto = Object.getPrototypeOf(proto);
    }

    // Check how movement is sent to server
    const requestMoveSrc = player.requestMovement ? player.requestMovement.toString().substring(0, 400) : 'not found';

    // Check socket.send to understand packets
    const socketSendSrc = socket?.send ? socket.send.toString().substring(0, 300) : 'not found';

    // Check game.player.follow or followPlayer
    const followSrc = player.follow ? player.follow.toString().substring(0, 400) : 'not found';

    // Check what happens at end of path
    const hasTargetSrc = player.hasTarget ? player.hasTarget.toString() : 'not found';
    const getTargetSrc = player.getTarget ? player.getTarget.toString().substring(0, 200) : 'not found';

    // Check current target
    const target = player.target;
    const targetInfo = target ? { instance: target.instance, type: target.type, gridX: target.gridX, gridY: target.gridY } : null;

    return { stepSrc, requestMoveSrc, followSrc, hasTargetSrc, getTargetSrc, socketSendSrc, targetInfo };
  });
  return JSON.stringify(info, null, 2);
}

