async (page) => {
  const info = await page.evaluate(() => {
    // Find what handles opcode 31
    const app = window.game.app || window.game;

    // Check game.messages or game.handlers
    const messageHandler = window.game.messages || window.game.app?.messages;
    const handlers = messageHandler ? Object.keys(messageHandler).filter(k => !isNaN(k)).slice(0, 40) : [];

    // Try to find the handler for opcode 31
    let handler31Src = 'not found';
    if (messageHandler && messageHandler[31]) {
      handler31Src = messageHandler[31].toString().substring(0, 400);
    }

    // Check packets enum for opcode 31
    // Look through game's known packets
    const gameKeys = Object.keys(window.game);

    // Check for a "packets" or "opcodes" enum in the code
    const findInBundle = () => {
      // Search for opcode 31 in loaded scripts (via internal references)
      try {
        const handler = window.game.socket?.messages?.[31];
        if (handler) return handler.toString().substring(0, 400);
      } catch(e) {}
      return null;
    };

    const bundleCheck = findInBundle();

    // Try to find the bubble/talk handler in the game
    const bubbleHandler = window.game.bubble || window.game.app?.bubble || window.game.info?.bubble;
    const bubbleKeys = bubbleHandler ? Object.getOwnPropertyNames(Object.getPrototypeOf(bubbleHandler)).slice(0, 15) : [];

    return { handlers, handler31Src, gameKeys: gameKeys.slice(0, 20), bundleCheck, bubbleKeys };
  });
  return JSON.stringify(info, null, 2);
}

